code = """import json
import pandas as pd

# Read company mapping from file
stockinfo_path = locals()['var_functions.query_db:30']
if isinstance(stockinfo_path, str):
    with open(stockinfo_path, 'r') as f:
        stockinfo_data = json.load(f)
else:
    stockinfo_data = locals()['var_functions.query_db:30']

company_map = {item['Symbol']: item['Company Description'] for item in stockinfo_data}

# Function to calculate volatility days
def calculate_volatility_days(data_path):
    if isinstance(data_path, str):
        with open(data_path, 'r') as f:
            data = json.load(f)
    else:
        data = data_path
    
    if not data:
        return 0, 0
    
    df = pd.DataFrame(data)
    df['High'] = pd.to_numeric(df['High'])
    df['Low'] = pd.to_numeric(df['Low'])
    df['range'] = df['High'] - df['Low']
    df['threshold'] = df['Low'] * 0.20
    df['exceeds_20pct'] = df['range'] > df['threshold']
    
    return int(df['exceeds_20pct'].sum()), len(df)

# Calculate for additional symbols
symbols_to_check = ["BCLI", "AGMH"]
paths = {
    "BCLI": locals()['var_functions.query_db:40'],
    "AGMH": locals()['var_functions.query_db:42']
}

all_results = [
    {'symbol': 'SES', 'company': company_map.get('SES', 'Unknown'), 'days_exceeding_20pct': 51, 'total_days': 252},
    {'symbol': 'IDEX', 'company': company_map.get('IDEX', 'Unknown'), 'days_exceeding_20pct': 15, 'total_days': 252},
    {'symbol': 'BHAT', 'company': company_map.get('BHAT', 'Unknown'), 'days_exceeding_20pct': 10, 'total_days': 110},
    {'symbol': 'CEMI', 'company': company_map.get('CEMI', 'Unknown'), 'days_exceeding_20pct': 3, 'total_days': 252},
    {'symbol': 'POPE', 'company': company_map.get('POPE', 'Unknown'), 'days_exceeding_20pct': 0, 'total_days': 252},
    {'symbol': 'PCSB', 'company': company_map.get('PCSB', 'Unknown'), 'days_exceeding_20pct': 0, 'total_days': 252},
    {'symbol': 'ANDA', 'company': company_map.get('ANDA', 'Unknown'), 'days_exceeding_20pct': 0, 'total_days': 209}
]

# Add results for the new symbols
for symbol in symbols_to_check:
    if symbol in paths:
        days, total = calculate_volatility_days(paths[symbol])
        all_results.append({
            'symbol': symbol,
            'company': company_map.get(symbol, 'Unknown'),
            'days_exceeding_20pct': days,
            'total_days': total
        })

# Get top 5 by days exceeding 20%
top_5 = sorted(all_results, key=lambda x: x['days_exceeding_20pct'], reverse=True)[:5]

# Extract just the company names for final answer
company_names = [result['company'] for result in top_5]

print('__RESULT__:')
print(json.dumps({
    'top_5_results': top_5,
    'company_names': company_names
}))"""

